from flask import Flask, redirect, request
from oauthlib.oauth2 import WebApplicationClient
import requests


class Config:
    # Insert your client configuration here
    CLIENT_ID = None
    CLIENT_SECRET = None
    DOMAIN = None  # The domain of your application


app = Flask(__name__)
app.config.from_object(Config)

client = WebApplicationClient(app.config["CLIENT_ID"])


def get_redirect_uri():
    # Use request to build the redirect_uri dynamically
    base_url = request.parsed_uri.scheme + "://" + request.parsed_uri.netloc
    return base_url + "/callback"


def validate_redirect_uri(redirect_uri):
    # Validate the redirect_uri to match the domain
    return app.config["DOMAIN"] in redirect_uri


@app.route("/login")
def login():
    # Build the authorization request
    redirect_uri = get_redirect_uri()

    if not validate_redirect_uri(redirect_uri):
        return "Invalid redirect_uri", 400

    authorization_endpoint = "https://provider.com/oauth/authorize"
    authorization_url, _ = client.prepare_request_uri(
        authorization_endpoint, redirect_uri=redirect_uri
    )

    return redirect(authorization_url)


@app.route("/callback")
def callback():
    # Retrieve the authorization code from the request
    code = request.args.get("code")

    # Prepare and send the token request
    token_endpoint = "https://provider.com/oauth/token"
    token_url, headers, body = client.prepare_token_request(
        token_endpoint,
        authorization_response=request.url,
        redirect_url=get_redirect_uri(),
        code=code
    )
    token_response = requests.post(
        token_url,
        headers=headers,
        data=body,
        auth=(app.config["CLIENT_ID"], app.config["CLIENT_SECRET"]),
    )

    client.parse_request_body_response(token_response.text)

    return "Logged in successfully"


